const input = $input.first().json;
const action = input.action || 'list';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

async function getCred(key) {
  const res = await helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.nextcloud-files&cred_key=eq.' + key + '&select=cred_value',
    headers: pgHeaders
  });
  return (res && res.length > 0) ? res[0].cred_value : null;
}

const ncUrl = await getCred('nextcloud_url');
const username = await getCred('nextcloud_username');
const password = await getCred('nextcloud_password');

if (!ncUrl || !username || !password) {
  return [{ json: { error: 'Nextcloud credentials not configured. Use add_credential to set nextcloud_url, nextcloud_username, and nextcloud_password.' } }];
}

const auth = 'Basic ' + Buffer.from(username + ':' + password).toString('base64');
const davBase = ncUrl.replace(/\/$/, '') + '/remote.php/dav/files/' + username + '/';

async function davRequest(method, url, body, extraHeaders) {
  const opts = {
    method,
    url,
    headers: { 'Authorization': auth, ...extraHeaders },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
    encoding: 'utf-8',
    json: false
  };
  if (body) opts.body = body;
  return await helpers.httpRequest(opts);
}

function normalizePath(p) {
  if (!p) return '';
  return p.replace(/^\/+/, '').replace(/\/+$/, '');
}

function buildUrl(path) {
  const p = normalizePath(path);
  if (!p) return davBase;
  return davBase + p.split('/').map(s => encodeURIComponent(s)).join('/');
}

function extractTagContent(xml, tag) {
  const patterns = [tag, tag.replace(':', '\\:')];
  for (const p of patterns) {
    const re = new RegExp('<' + p + '[^>]*>([\\s\\S]*?)</' + p + '>', 'g');
    const matches = [];
    let m;
    while ((m = re.exec(xml)) !== null) matches.push(m[1].trim());
    if (matches.length > 0) return matches;
  }
  return [];
}

function formatSize(bytes) {
  if (!bytes || bytes === '0') return '0 B';
  const n = Number(bytes);
  if (n < 1024) return n + ' B';
  if (n < 1024 * 1024) return (n / 1024).toFixed(1) + ' KB';
  if (n < 1024 * 1024 * 1024) return (n / (1024 * 1024)).toFixed(1) + ' MB';
  return (n / (1024 * 1024 * 1024)).toFixed(1) + ' GB';
}

// === list ===
if (action === 'list') {
  const path = input.path || '/';
  try {
    const propfindXml = '<?xml version="1.0" encoding="utf-8"?><d:propfind xmlns:d="DAV:" xmlns:oc="http://owncloud.org/ns"><d:prop><d:getlastmodified/><d:getcontenttype/><d:getcontentlength/><d:resourcetype/><oc:size/></d:prop></d:propfind>';
    const resp = await davRequest('PROPFIND', buildUrl(path), propfindXml,
      { 'Depth': '1', 'Content-Type': 'application/xml; charset=utf-8' }
    );
    if (resp.statusCode === 404) {
      return [{ json: { error: 'Path not found: /' + normalizePath(path) } }];
    }
    const body = resp.body || '';
    const responses = body.split('<d:response>').slice(1);
    const items = [];
    let isFirst = true;
    for (const block of responses) {
      if (isFirst) { isFirst = false; continue; }
      const hrefs = extractTagContent('<d:response>' + block, 'd:href');
      const href = hrefs.length > 0 ? decodeURIComponent(hrefs[0]) : '';
      const parts = href.replace(/\/$/, '').split('/');
      const name = parts[parts.length - 1];
      const isFolder = block.includes('<d:collection');
      const sizes = extractTagContent('<d:response>' + block, 'd:getcontentlength').concat(extractTagContent('<d:response>' + block, 'oc:size'));
      const size = sizes.length > 0 ? sizes[0] : '0';
      const types = extractTagContent('<d:response>' + block, 'd:getcontenttype');
      const modified = extractTagContent('<d:response>' + block, 'd:getlastmodified');
      items.push({
        name,
        type: isFolder ? 'folder' : 'file',
        size: formatSize(size),
        contentType: types.length > 0 ? types[0] : (isFolder ? 'folder' : 'unknown'),
        modified: modified.length > 0 ? modified[0] : ''
      });
    }
    if (items.length === 0) {
      return [{ json: { result: 'Folder /' + normalizePath(path) + ' is empty.' } }];
    }
    const folders = items.filter(i => i.type === 'folder');
    const files = items.filter(i => i.type === 'file');
    let result = 'Contents of /' + normalizePath(path) + ' (' + items.length + ' items):\n\n';
    if (folders.length > 0) {
      result += 'Folders:\n';
      for (const f of folders) result += '  \uD83D\uDCC1 ' + f.name + '/\n';
      result += '\n';
    }
    if (files.length > 0) {
      result += 'Files:\n';
      for (const f of files) result += '  \uD83D\uDCC4 ' + f.name + ' (' + f.size + ', ' + f.contentType + ')\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list files: ' + err.message } }];
  }

// === read ===
} else if (action === 'read') {
  const path = input.path;
  if (!path) return [{ json: { error: 'Parameter "path" is required.' } }];
  try {
    const resp = await davRequest('GET', buildUrl(path), null, {});
    if (resp.statusCode === 404) {
      return [{ json: { error: 'File not found: /' + normalizePath(path) } }];
    }
    if (resp.statusCode >= 400) {
      return [{ json: { error: 'Failed to read file. Status: ' + resp.statusCode } }];
    }
    const content = resp.body || '';
    const ct = resp.headers && (resp.headers['content-type'] || '');
    const cl = resp.headers && (resp.headers['content-length'] || '0');
    if (content.length > 100000) {
      return [{ json: { result: 'File /' + normalizePath(path) + ' is too large to display (' + formatSize(cl) + '). Only text files under 100KB are supported.', contentType: ct, size: formatSize(cl) } }];
    }
    return [{ json: { result: content, path: '/' + normalizePath(path), contentType: ct, size: formatSize(cl) } }];
  } catch (err) {
    return [{ json: { error: 'Failed to read file: ' + err.message } }];
  }

// === write ===
} else if (action === 'write') {
  const path = input.path;
  const content = input.content;
  if (!path || content === undefined || content === null) {
    return [{ json: { error: 'Parameters required: path, content.' } }];
  }
  try {
    const resp = await davRequest('PUT', buildUrl(path), content, {
      'Content-Type': 'text/plain; charset=utf-8',
      'X-NC-WebDAV-AutoMkcol': '1'
    });
    if (resp.statusCode >= 200 && resp.statusCode < 300) {
      return [{ json: { result: 'File written: /' + normalizePath(path) + ' (' + formatSize(String(content.length)) + ')' } }];
    }
    return [{ json: { error: 'Failed to write file. Status: ' + resp.statusCode + ' Body: ' + (resp.body || '').substring(0, 300) } }];
  } catch (err) {
    return [{ json: { error: 'Failed to write file: ' + err.message } }];
  }

// === upload_url ===
} else if (action === 'upload_url') {
  const url = input.url;
  const path = input.path;
  if (!url || !path) {
    return [{ json: { error: 'Parameters required: url (source URL), path (destination on Nextcloud).' } }];
  }
  try {
    const dlResp = await helpers.httpRequest({
      method: 'GET',
      url: url,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
      encoding: 'arraybuffer'
    });
    if (dlResp.statusCode >= 400) {
      return [{ json: { error: 'Failed to download from URL. Status: ' + dlResp.statusCode } }];
    }
    const fileBuffer = dlResp.body;
    const ct = dlResp.headers && (dlResp.headers['content-type'] || 'application/octet-stream');
    const uploadResp = await helpers.httpRequest({
      method: 'PUT',
      url: buildUrl(path),
      headers: {
        'Authorization': auth,
        'Content-Type': ct,
        'X-NC-WebDAV-AutoMkcol': '1'
      },
      body: fileBuffer,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
      encoding: 'arraybuffer'
    });
    if (uploadResp.statusCode >= 200 && uploadResp.statusCode < 300) {
      const size = fileBuffer.byteLength || fileBuffer.length || 0;
      return [{ json: { result: 'File uploaded: /' + normalizePath(path) + ' (' + formatSize(String(size)) + ')', path: '/' + normalizePath(path), size: formatSize(String(size)) } }];
    }
    return [{ json: { error: 'Failed to upload file. Status: ' + uploadResp.statusCode } }];
  } catch (err) {
    return [{ json: { error: 'Failed to upload from URL: ' + err.message } }];
  }

// === mkdir ===
} else if (action === 'mkdir') {
  const path = input.path;
  if (!path) return [{ json: { error: 'Parameter "path" is required.' } }];
  try {
    const resp = await davRequest('MKCOL', buildUrl(path) + '/', null, {});
    if (resp.statusCode === 201) {
      return [{ json: { result: 'Folder created: /' + normalizePath(path) } }];
    }
    if (resp.statusCode === 405) {
      return [{ json: { result: 'Folder already exists: /' + normalizePath(path) } }];
    }
    return [{ json: { error: 'Failed to create folder. Status: ' + resp.statusCode + ' Body: ' + (resp.body || '').substring(0, 300) } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create folder: ' + err.message } }];
  }

// === delete ===
} else if (action === 'delete') {
  const path = input.path;
  if (!path) return [{ json: { error: 'Parameter "path" is required.' } }];
  try {
    const resp = await davRequest('DELETE', buildUrl(path), null, {});
    if (resp.statusCode >= 200 && resp.statusCode < 300) {
      return [{ json: { result: 'Deleted: /' + normalizePath(path) } }];
    }
    if (resp.statusCode === 404) {
      return [{ json: { error: 'Not found: /' + normalizePath(path) } }];
    }
    return [{ json: { error: 'Failed to delete. Status: ' + resp.statusCode + ' Body: ' + (resp.body || '').substring(0, 300) } }];
  } catch (err) {
    return [{ json: { error: 'Failed to delete: ' + err.message } }];
  }

// === move ===
} else if (action === 'move') {
  const source = input.source;
  const destination = input.destination;
  if (!source || !destination) {
    return [{ json: { error: 'Parameters required: source, destination.' } }];
  }
  try {
    const resp = await davRequest('MOVE', buildUrl(source), null, {
      'Destination': buildUrl(destination),
      'Overwrite': 'F'
    });
    if (resp.statusCode >= 200 && resp.statusCode < 300) {
      return [{ json: { result: 'Moved: /' + normalizePath(source) + ' \u2192 /' + normalizePath(destination) } }];
    }
    if (resp.statusCode === 404) {
      return [{ json: { error: 'Source not found: /' + normalizePath(source) } }];
    }
    if (resp.statusCode === 412) {
      return [{ json: { error: 'Destination already exists: /' + normalizePath(destination) } }];
    }
    return [{ json: { error: 'Failed to move. Status: ' + resp.statusCode + ' Body: ' + (resp.body || '').substring(0, 300) } }];
  } catch (err) {
    return [{ json: { error: 'Failed to move: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use list, read, write, upload_url, mkdir, delete, or move.' } }];
}
